// Lazy initialization for expensive computations
const [data, setData] = useState(() => computeExpensiveInitialValue());

// Object state update — always immutable
const [user, setUser] = useState<User>({ name: '', email: '' });
const updateName = (name: string) => setUser(prev => ({ ...prev, name }));

// Functional update to avoid stale closure
const [count, setCount] = useState(0);
const increment = () => setCount(c => c + 1);  // not count + 1

useEffect(() => {
  const controller = new AbortController();

  async function fetchData() {
    try {
      const response = await fetch(url, { signal: controller.signal });
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      setData(await response.json());
    } catch (error) {
      if (error instanceof Error && error.name !== 'AbortError') {
        setError(error);
      }
    }
  }

  fetchData();
  return () => controller.abort();
}, [url]);

function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebouncedValue(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);  // exhaustive deps: both value and delay

  return debouncedValue;
}

type State = { items: Item[]; isLoading: boolean; error: Error | null };
type Action =
  | { type: 'FETCH_START' }
  | { type: 'FETCH_SUCCESS'; payload: Item[] }
  | { type: 'FETCH_ERROR'; payload: Error };

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'FETCH_START':  return { ...state, isLoading: true, error: null };
    case 'FETCH_SUCCESS': return { ...state, isLoading: false, items: action.payload };
    case 'FETCH_ERROR':  return { ...state, isLoading: false, error: action.payload };
    default: return state;
  }
}
